const data = $input.first().json;

// Validate required fields
const requiredFields = ['workflow_name', 'log_type', 'action'];
const missing = requiredFields.filter(f => !data[f]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Validate log_type enum
const validLogTypes = ['ai_call', 'action', 'error', 'audit'];
if (!validLogTypes.includes(data.log_type)) {
  throw new Error(`Invalid log_type: "${data.log_type}". Must be one of: ${validLogTypes.join(', ')}`);
}

// Validate status enum
const status = data.status || 'success';
if (!['success', 'failure'].includes(status)) {
  throw new Error(`Invalid status: "${status}". Must be 'success' or 'failure'`);
}

// Prepare validated output with all fields
return [{
  json: {
    workflow_name: data.workflow_name,
    execution_id: data.execution_id || null,
    log_type: data.log_type,
    action: data.action,
    input_payload: data.input_payload
      ? (typeof data.input_payload === 'string' ? data.input_payload : JSON.stringify(data.input_payload))
      : null,
    output_payload: data.output_payload
      ? (typeof data.output_payload === 'string' ? data.output_payload : JSON.stringify(data.output_payload))
      : null,
    model: data.model || null,
    tokens_input: data.tokens_input ?? null,
    tokens_output: data.tokens_output ?? null,
    latency_ms: data.latency_ms ?? null,
    cost_usd: data.cost_usd ?? null,
    status: status,
    error_message: data.error_message || null
  }
}];

const result = $input.first().json;

return [{
  json: {
    success: true,
    log_id: result.id || null
  }
}];
